import React, { useRef, useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useToast } from '../../context/ToastContext';

const Logo = () => (
  <div style={{display:'flex',alignItems:'center',gap:12,justifyContent:'center',marginBottom:24}}>
    <div style={{width:42,height:42,background:'var(--g-brand)',borderRadius:12,display:'flex',alignItems:'center',justifyContent:'center',boxShadow:'0 6px 20px rgba(99,102,241,.5)'}}>
      <span style={{color:'#fff',fontFamily:'var(--ff-h)',fontWeight:800,fontSize:21}}>D</span>
    </div>
    <span style={{fontFamily:'var(--ff-h)',fontWeight:800,fontSize:22,letterSpacing:'-0.03em'}}>DeLaxiY</span>
  </div>
);

export default function AuthModal({ mode, onClose, onSwitch }) {
  const { login, register, loading } = useAuth();
  const { add }   = useToast();
  const navigate  = useNavigate();

  // ── Uncontrolled refs — no focus loss ever ──────────────────────────────
  const nameRef    = useRef(null);
  const emailRef   = useRef(null);
  const pwRef      = useRef(null);
  const cfmRef     = useRef(null);

  const [errs,    setErrs]    = useState({});
  const [show,    setShow]    = useState(false);
  const [showC,   setShowC]   = useState(false);

  // Password strength derived from ref value — updated via a dummy state tick
  const [pwLen,   setPwLen]   = useState(0);

  useEffect(() => {
    // Focus name field on register, email on login
    setTimeout(() => {
      if (mode === 'register' && nameRef.current)  nameRef.current.focus();
      else if (emailRef.current)                   emailRef.current.focus();
    }, 50);
  }, []); // eslint-disable-line

  // ── Live validation helpers ─────────────────────────────────────────────
  function chkName(v)    { return !v.trim() ? 'Please fill the field' : v.trim().length < 2 ? 'Min 2 characters' : ''; }
  function chkEmail(v)   { return !v.trim() ? 'Please fill the field' : !/^[^@]+@[^@]+\.[^@]+$/.test(v) ? 'Enter a valid email' : ''; }
  function chkPw(v)      { return !v ? 'Please fill the field' : v.length < 6 ? 'Minimum 6 characters' : ''; }
  function chkCfm(v, pw) { return !v ? 'Please fill the field' : v !== pw ? 'Passwords do not match' : ''; }

  // ── Submit ───────────────────────────────────────────────────────────────
  async function submit(e) {
    e.preventDefault();
    const name  = nameRef.current?.value  || '';
    const email = emailRef.current?.value || '';
    const pw    = pwRef.current?.value    || '';
    const cfm   = cfmRef.current?.value   || '';

    const ev = {};
    if (mode === 'register') { const n = chkName(name);  if (n) ev.name     = n; }
    const em = chkEmail(email);                           if (em) ev.email    = em;
    const pe = chkPw(pw);                                 if (pe) ev.password = pe;
    if (mode === 'register') { const c = chkCfm(cfm,pw); if (c) ev.confirm  = c; }

    if (Object.keys(ev).length) { setErrs(ev); return; }
    setErrs({});

    try {
      if (mode === 'login') await login(email, pw);
      else                  await register(name, email, pw);
      add(mode === 'login' ? '🎉 Welcome back!' : '🚀 Account created!', 'success');
      onClose();
      navigate('/dashboard');
    } catch(err) {
      setErrs({ _: err.message });
    }
  }

  // ── Styles ───────────────────────────────────────────────────────────────
  const IS = (key) => ({
    background: 'rgba(255,255,255,0.05)',
    border: `1.5px solid ${errs[key] ? '#f43f5e' : 'var(--border2)'}`,
    borderRadius: 'var(--r2)',
    padding: '11px 15px',
    color: 'var(--t1)',
    fontFamily: 'var(--ff-b)',
    fontSize: '14px',
    width: '100%',
    outline: 'none',
    transition: 'border-color .2s, box-shadow .2s',
    boxSizing: 'border-box',
  });

  const onFocus = e => {
    e.target.style.borderColor = 'var(--indigo)';
    e.target.style.boxShadow   = '0 0 0 3px rgba(99,102,241,.15)';
  };
  const onBlur = (key, val) => {
    const checks = { name: chkName, email: chkEmail, password: chkPw };
    const err = checks[key] ? checks[key](val) : '';
    setErrs(p => ({ ...p, [key]: err }));
  };

  // Strength
  const pw = pwRef.current?.value || '';
  const strength = !pw ? 0 : pw.length < 6 ? 1 : pw.length < 10 ? 2 : /[A-Z]/.test(pw)&&/[0-9]/.test(pw) ? 4 : 3;
  const sColor   = ['transparent','#f43f5e','#f59e0b','#06b6d4','#10b981'][strength];
  const sLabel   = ['','Weak','Fair','Good','Strong'][strength];

  // Field wrapper
  const F = ({ id, label, err, ok, children }) => (
    <div style={{display:'flex',flexDirection:'column',gap:5}}>
      <label htmlFor={id} style={{fontSize:'11px',fontWeight:700,color:'var(--t2)',textTransform:'uppercase',letterSpacing:'.05em'}}>
        {label}
      </label>
      {children}
      {err
        ? <span style={{fontSize:'12px',color:'#f43f5e',display:'flex',alignItems:'center',gap:4,fontWeight:500}}><span style={{fontSize:9}}>●</span>{err}</span>
        : ok
        ? <span style={{fontSize:'12px',color:'#10b981',display:'flex',alignItems:'center',gap:4}}><span>✓</span>{ok}</span>
        : null
      }
    </div>
  );

  return (
    <div className="overlay" onClick={e => e.target === e.currentTarget && onClose()}>
      <div className="modal modal-sm scale-in" onClick={e => e.stopPropagation()}>
        <div style={{height:4,background:'var(--g-brand)',borderRadius:'var(--r4) var(--r4) 0 0'}}/>

        <div style={{padding:'30px 32px 24px'}}>
          <Logo />

          <div style={{textAlign:'center',marginBottom:22}}>
            <h2 style={{fontSize:20,marginBottom:5}}>{mode==='login'?'Welcome back':'Create account'}</h2>
            <p style={{fontSize:13,color:'var(--t2)'}}>{mode==='login'?'Sign in to your DeLaxiY account':'Start managing orders and dashboards'}</p>
          </div>

          {errs._ && (
            <div style={{background:'rgba(244,63,94,.12)',border:'1px solid rgba(244,63,94,.3)',borderRadius:'var(--r2)',padding:'10px 14px',color:'#f43f5e',fontSize:13,marginBottom:14,display:'flex',alignItems:'center',gap:8}}>
              <span>✕</span> {errs._}
            </div>
          )}

          <form onSubmit={submit} style={{display:'flex',flexDirection:'column',gap:14}} noValidate>

            {/* Full Name — register only */}
            {mode === 'register' && (
              <F id="am-name" label="Full Name" err={errs.name}>
                <input
                  id="am-name" ref={nameRef}
                  name="fullname" type="text"
                  placeholder="Enter your full name"
                  defaultValue=""
                  style={IS('name')}
                  onFocus={onFocus}
                  onBlur={e => onBlur('name', e.target.value)}
                  onChange={e => setErrs(p => ({...p, name: chkName(e.target.value)}))}
                  autoComplete="name"
                />
              </F>
            )}

            {/* Email */}
            <F id="am-email" label="Email Address" err={errs.email}>
              <input
                id="am-email" ref={emailRef}
                name="email" type="email"
                placeholder="you@example.com"
                defaultValue=""
                style={IS('email')}
                onFocus={onFocus}
                onBlur={e => onBlur('email', e.target.value)}
                onChange={e => setErrs(p => ({...p, email: chkEmail(e.target.value)}))}
                autoComplete="email"
              />
            </F>

            {/* Password */}
            <F id="am-pwd" label="Password" err={errs.password}>
              <div style={{position:'relative'}}>
                <input
                  id="am-pwd" ref={pwRef}
                  name="password"
                  type={show ? 'text' : 'password'}
                  placeholder="Minimum 6 characters"
                  defaultValue=""
                  style={{...IS('password'), paddingRight:44}}
                  onFocus={onFocus}
                  onBlur={e => onBlur('password', e.target.value)}
                  onChange={e => {
                    setPwLen(e.target.value.length); // triggers strength bar re-render
                    setErrs(p => ({...p, password: chkPw(e.target.value)}));
                  }}
                  autoComplete={mode==='login'?'current-password':'new-password'}
                />
                <button type="button" onClick={() => setShow(!show)}
                  style={{position:'absolute',right:12,top:'50%',transform:'translateY(-50%)',background:'none',border:'none',color:'var(--t2)',cursor:'pointer',fontSize:15,padding:2}}>
                  {show ? '🙈' : '👁'}
                </button>
              </div>
              {/* Password strength — register only */}
              {mode === 'register' && pwLen > 0 && (
                <div style={{marginTop:6}}>
                  <div style={{display:'flex',gap:4}}>
                    {[1,2,3,4].map(i => (
                      <div key={i} style={{flex:1,height:3,borderRadius:99,background:i<=strength?sColor:'var(--border2)',transition:'background .3s'}}/>
                    ))}
                  </div>
                  <span style={{fontSize:11,color:sColor,fontWeight:600,marginTop:3,display:'block'}}>{sLabel}</span>
                </div>
              )}
            </F>

            {/* Confirm Password — register only */}
            {mode === 'register' && (
              <F id="am-conf" label="Confirm Password" err={errs.confirm}>
                <div style={{position:'relative'}}>
                  <input
                    id="am-conf" ref={cfmRef}
                    name="confirmPassword"
                    type={showC ? 'text' : 'password'}
                    placeholder="Repeat your password"
                    defaultValue=""
                    style={{...IS('confirm'), paddingRight:44}}
                    onFocus={onFocus}
                    onBlur={e => setErrs(p => ({...p, confirm: chkCfm(e.target.value, pwRef.current?.value||'')}))}
                    onChange={e => setErrs(p => ({...p, confirm: chkCfm(e.target.value, pwRef.current?.value||'')}))}
                    autoComplete="new-password"
                  />
                  <button type="button" onClick={() => setShowC(!showC)}
                    style={{position:'absolute',right:12,top:'50%',transform:'translateY(-50%)',background:'none',border:'none',color:'var(--t2)',cursor:'pointer',fontSize:15,padding:2}}>
                    {showC ? '🙈' : '👁'}
                  </button>
                </div>
              </F>
            )}

            {/* Submit */}
            <button type="submit" disabled={loading}
              style={{
                width:'100%', justifyContent:'center', padding:'13px',
                fontSize:15, marginTop:4, borderRadius:'var(--r2)',
                background:'var(--g-brand)', color:'#fff', border:'none',
                cursor: loading ? 'not-allowed' : 'pointer',
                fontFamily:'var(--ff-b)', fontWeight:700,
                display:'flex', alignItems:'center', gap:8,
                boxShadow:'0 4px 16px rgba(99,102,241,.4)',
                transition:'all .2s', opacity: loading ? .7 : 1,
              }}>
              {loading
                ? <><span className="spinner" style={{borderTopColor:'#fff'}}/>{mode==='login'?' Signing in…':' Creating account…'}</>
                : mode === 'login' ? '→ Sign In' : '→ Create Account'
              }
            </button>
          </form>

          <div style={{textAlign:'center',marginTop:18,fontSize:13,color:'var(--t2)'}}>
            {mode === 'login'
              ? <>Don't have an account?{' '}
                  <button type="button" onClick={() => onSwitch('register')}
                    style={{background:'none',border:'none',color:'var(--indigo)',cursor:'pointer',fontWeight:700,fontSize:13}}>
                    Register free
                  </button>
                </>
              : <>Already have an account?{' '}
                  <button type="button" onClick={() => onSwitch('login')}
                    style={{background:'none',border:'none',color:'var(--indigo)',cursor:'pointer',fontWeight:700,fontSize:13}}>
                    Sign in
                  </button>
                </>
            }
          </div>
        </div>
      </div>
    </div>
  );
}
